import { initBridge } from './hydra.js';

let bridge;
if (window.name.startsWith('hydra')) {
    bridge = initBridge({
        pageBlocksFields: [
            { fieldName: 'blocks', title: 'Content',
              allowedBlocks: ['slate', 'grid', 'myimage'] },
        ],
    });
}

bridge = initBridge({
    pageBlocksFields: [
        { fieldName: 'header_blocks', title: 'Header',
          allowedBlocks: ['slate', 'image'], maxLength: 3 },
        { fieldName: 'blocks', title: 'Content',
          allowedBlocks: ['slate', 'image', 'hero', 'columns'] },
        { fieldName: 'footer_blocks', title: 'Footer',
          allowedBlocks: ['slate', 'link'] }
    ],
});

const bridge = initBridge({
    ...,
    onEditChange: (formData) => renderPage(formData),
});

if (!window.name.startsWith('hydra-edit')) {
    // Normal page render from server
    renderPage(await fetchContent(path));
}

const bridge = initBridge({
    pageBlocksFields: [
        { fieldName: 'blocks', title: 'Content',
          allowedBlocks: ['slate', 'image', 'video', 'slider'] },
    ],
    voltoConfig: {
        blocks: {
            blocksConfig: {
                slider: {
                    id: 'slider',
                    title: 'Slider',
                    group: 'common',
                    blockSchema: {
                        properties: {
                            slider_timing: {
                                title: 'Delay',
                                widget: 'float',
                            },
                            slides: {
                                title: 'Slides',
                                widget: 'blocks_layout',
                                allowedBlocks: ['slide', 'image'],
                                defaultBlockType: 'slide',
                            }
                        },
                    }
                },
                slide: {
                    id: 'slide',
                    title: 'Slide',
                    blockSchema: {
                        properties: {
                            url: { title: 'Link', widget: 'url' },
                            title: { title: 'Title' },
                            image: { title: 'Image', widget: 'image' },
                            description: { title: 'Description',
                                           widget: 'slate' },
                        },
                    },
                },
            },
        },
    },
});
